WITH incoming AS (SELECT "from_address", SUM("value") AS "total_incoming" FROM "ETHEREUM_BLOCKCHAIN"."TRACES" WHERE "status" = 1 AND "from_address" IS NOT NULL GROUP BY "from_address"), outgoing AS (SELECT "to_address", SUM("value") AS "total_outgoing" FROM "ETHEREUM_BLOCKCHAIN"."TRACES" WHERE "status" = 1 AND "to_address" IS NOT NULL GROUP BY "to_address"), miner_rewards AS (SELECT t."from_address", SUM(t."gas_price" * t."receipt_gas_used") AS "total_rewards" FROM "ETHEREUM_BLOCKCHAIN"."TRANSACTIONS" t GROUP BY t."from_address"), gas_fees AS (SELECT t."from_address", SUM(t."gas") AS "total_gas_fees" FROM "ETHEREUM_BLOCKCHAIN"."TRANSACTIONS" t GROUP BY t."from_address") SELECT COALESCE(i."from_address", o."to_address") AS "address", COALESCE(i."total_incoming", 0) - COALESCE(o."total_outgoing", 0) + COALESCE(m."total_rewards", 0) - COALESCE(g."total_gas_fees", 0) AS "net_balance" FROM incoming i FULL OUTER JOIN outgoing o ON i."from_address" = o."to_address" FULL OUTER JOIN miner_rewards m ON COALESCE(i."from_address", o."to_address") = m."from_address" FULL OUTER JOIN gas_fees g ON COALESCE(i."from_address", o."to_address") = g."from_address" WHERE COALESCE(i."from_address", o."to_address") IS NOT NULL
